{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.MsgE1];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.MsgE1, fireflyTranId);
        inst.gateways[GatewayKey.GateE].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.MsgE2];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.MsgE2, fireflyTranId);
        inst.events[EventKey.EndEvent_E].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Gateway storage g = inst.gateways[GatewayKey.GateE];
        require(g.exists, "gateway not set");
        require(g.state == ElementState.ENABLED, "gateway state not allowed");

        g.state = ElementState.COMPLETED;
        emit GatewayDone(instanceId, GatewayKey.GateE);
        if (inst.stateMemory.ContinueE == true) {
            inst.messages[MessageKey.MsgE2].state = ElementState.ENABLED;
        }
        else {
            inst.events[EventKey.EndEvent_E].state = ElementState.ENABLED;
        }

    }

{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.EndEvent_E];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.EndEvent_E);

    }
